//External Lib Import
import { createSlice } from "@reduxjs/toolkit";

const EmployeeSlice = createSlice({
  name: "Employee",
  initialState: {
    EmployeeLists: [],
    EmployeeDropDown: [],
    TotalEmployee: 0,
    DepartmentHeadsList: [],
    StaffList: [],
    EmployeeDetails: {
      DepartmentId: "",
      Department: "",
      FirstName: "",
      LastName: "",
      Gender: "",
      DateOfBirth: "",
      Address: "",
      Phone: "",
      Email: "",
      Password: "",
      Roles: "STAFF",
      Image:
        "data:image/png;base64,",
    },
  },
  reducers: {
    SetEmployeeLists(state, action) {
      state.EmployeeLists = action.payload;
    },
    SetTotalEmployee(state, action) {
      state.TotalEmployee = action.payload;
    },
    SetEmployeeDropDown(state, action) {
      state.EmployeeDropDown = action.payload;
    },
    SetEmployeeDetails(state, action) {
      state.EmployeeDetails = action.payload;
    },
    SetDepartmentHeadsList(state, action) {
      state.DepartmentHeadsList = action.payload;
    },
    SetStaffList(state, action) {
      state.StaffList = action.payload;
    },
    ResetEmployeeDetails(state, action) {
      state.EmployeeDetails = {
        DepartmentId: "",
        Department: "",
        FirstName: "",
        LastName: "",
        Gender: "",
        DateOfBirth: "",
        Address: "",
        Phone: "",
        Email: "",
        Password: "",
        Roles: "STAFF",
        Image:
          "data:image/png;base64,",
      };
    },
  },
});

export const {
  SetEmployeeLists,
  SetTotalEmployee,
  SetEmployeeDropDown,
  SetEmployeeDetails,
  ResetEmployeeDetails,
  SetDepartmentHeadsList,
  SetStaffList,
} = EmployeeSlice.actions;
export default EmployeeSlice.reducer;
